 1→import { describe, expect, it } from "bun:test";
 2→import { RecordId } from "surrealdb";
 3→import { resolveEntityProject } from "../../app/src/server/workspace/workspace-scope";
 4→
 5→function makeProject(id: string, name: string) {
 6→  return { id: new RecordId("project", id), name };
 7→}
 8→
 9→describe("resolveEntityProject", () => {
10→  it("returns undefined when no projects exist", () => {
11→    expect(resolveEntityProject("auth feature", "We need auth", [])).toBeUndefined();
12→  });
13→
14→  it("auto-assigns to the only project regardless of text", () => {
15→    const project = makeProject("p1", "Atlas");
16→    expect(resolveEntityProject("unrelated feature", "some text", [project])).toBe(project.id);
17→  });
18→
19→  it("matches the correct project when one name appears in prompt text", () => {
