190→/** Match directory paths against project names using normalized token overlap */
191→function matchPathToProject(
192→  paths: string[],
193→  projects: ProjectRow[],
194→): RecordId<"project", string> | undefined {
195→  const pathTokens = new Set<string>();
196→  for (const p of paths) {
197→    for (const segment of p.split("/").filter(Boolean)) {
198→      for (const token of segment.toLowerCase().replace(/[^a-z0-9]/g, " ").split(/\s+/)) {
199→        if (token.length > 2) pathTokens.add(token);
200→      }
201→    }
202→  }
203→
204→  if (pathTokens.size === 0) return undefined;
205→
206→  let bestProject: ProjectRow | undefined;
207→  let bestOverlap = 0;
208→
209→  for (const project of projects) {
210→    const nameTokens = new Set(
211→      project.name.toLowerCase().replace(/[^a-z0-9]/g, " ").split(/\s+/).filter((t) => t.length > 2),
212→    );
213→    let overlap = 0;
214→    for (const token of nameTokens) {
215→      if (pathTokens.has(token)) overlap++;
216→    }
217→    if (overlap > bestOverlap) {
218→      bestOverlap = overlap;
219→      bestProject = project;
220→    }
221→  }
222→
223→  return bestProject ? bestProject.id : undefined;
224→}
