123→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
124→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
125→  if (!response.ok || !response.body) {
126→    throw new Error(`Failed to open SSE stream (${response.status})`);
127→  }
128→
129→  const reader = response.body.getReader();
130→  const decoder = new TextDecoder();
131→  const events: T[] = [];
132→  let buffer = "";
133→
134→  const timeout = setTimeout(() => {
135→    void reader.cancel();
136→  }, timeoutMs);
137→
138→  try {
139→    while (true) {
140→      const { value, done } = await reader.read();
141→      if (done) {
142→        break;
143→      }
144→
145→      buffer += decoder.decode(value, { stream: true });
146→      const segments = buffer.split("\n\n");
147→      buffer = segments.pop() ?? "";
148→
149→      for (const segment of segments) {
150→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
151→        if (!dataLine) {
152→          continue;
153→        }
154→
155→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
156→        events.push(event);
157→
158→        if (event.type === "error") {
159→          const errorText = (event as { error?: string }).error;
160→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
161→        }
162→
163→        if (event.type === "done") {
164→          return events;
165→        }
166→      }
167→    }
168→  } finally {
169→    clearTimeout(timeout);
170→    reader.releaseLock();
171→  }
172→
173→  return events;
174→}
