158→        if (event.type === "error") {
159→          const errorText = (event as { error?: string }).error;
160→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
161→        }
162→
163→        if (event.type === "done") {
164→          return events;
165→        }
166→      }
167→    }
168→  } finally {
169→    clearTimeout(timeout);
170→    reader.releaseLock();
171→  }
172→
