  // ---- Auth ----

  it("rejects request without auth header", async () => {
    const { baseUrl, surreal } = getRuntime();
    const ws = await createWorkspaceWithApiKey(baseUrl, surreal);

    const response = await fetch(`${baseUrl}/api/mcp/${ws.workspaceId}/context`, {
      method: "POST",
