135→    const workspace = await createOnboardedWorkspace(baseUrl, surreal);
136→
137→    // Seed a project so the PM agent has something to scope tasks under
138→    const projectRecord = new RecordId("project", randomUUID());
139→    const workspaceRecord = new RecordId("workspace", workspace.workspaceId);
140→    await surreal.create(projectRecord).content({
141→      name: "Brain Platform",
142→      status: "active",
143→      workspace: workspaceRecord,
144→      created_at: new Date(),
145→      updated_at: new Date(),
146→    });
147→    await surreal
148→      .relate(workspaceRecord, new RecordId("has_project", randomUUID()), projectRecord, {
149→        added_at: new Date(),
150→      })
151→      .output("after");
152→
153→    const message = await fetchJson<ChatMessageResponse>(`${baseUrl}/api/chat/messages`, {
154→      method: "POST",
155→      headers: { "Content-Type": "application/json" },
156→      body: JSON.stringify({
157→        clientMessageId: randomUUID(),
158→        workspaceId: workspace.workspaceId,
159→        conversationId: workspace.conversationId,
160→        text: "Add a task for implementing user authentication for Brain Platform.",
161→      }),
162→    });
163→
164→    const events = await collectSseEvents<StreamEvent>(`${baseUrl}${message.streamUrl}`, 120_000);
165→    const assistantEvent = events.find((event) => event.type === "assistant_message");
166→    expect(assistantEvent).toBeDefined();
167→
168→    // The PM agent should create a task directly or return a suggestion.
169→    // Check for either: a task in DB or a WorkItemSuggestionList in the response.
170→    const [taskRows] = await surreal
171→      .query<[Array<{ id: RecordId<"task", string>; title: string }>]>(
172→        "SELECT id, title FROM task WHERE workspace = $workspace;",
173→        { workspace: workspaceRecord },
174→      )
175→      .collect<[Array<{ id: RecordId<"task", string>; title: string }>]>();
176→
177→    if (!assistantEvent || assistantEvent.type !== "assistant_message") {
178→      throw new Error("Expected assistant_message event");
179→    }
180→
181→    const hasTaskInDb = taskRows.length > 0;
182→    const hasSuggestionInResponse = assistantEvent.text.includes("WorkItemSuggestionList");
183→    const responseAcknowledgesTask =
184→      assistantEvent.text.toLowerCase().includes("authentication") ||
185→      assistantEvent.text.toLowerCase().includes("task");
186→    expect(hasTaskInDb || hasSuggestionInResponse || responseAcknowledgesTask).toBe(true);
187→  }, 180_000);
188→});
