# Quick inline test: start server, create workspace, set api key, hit endpoint, check stderr
PORT=19876
NS="debug_intent_$(date +%s)"
DB="debug_intent_db"

# Setup surreal namespace/db  
bun -e "
const { Surreal } = require('surrealdb');
const { readFileSync, readdirSync } = require('node:fs');
const { join } = require('node:path');
async function main() {
  const s = new Surreal();
  await s.connect('ws://127.0.0.1:8000/rpc');
  await s.signin({username:'root',password:'root'});
  await s.query('DEFINE NAMESPACE $NS;'.replace('\$NS','${NS}'));
  await s.use({namespace:'${NS}'});
  await s.query('DEFINE DATABASE ${DB};');
  await s.use({namespace:'${NS}',database:'${DB}'});
  const schema = readFileSync(join('${PWD}','schema','surreal-schema.surql'),'utf8');
  await s.query(schema);
  const dir = join('${PWD}','schema','migrations');
  for (const f of readdirSync(dir).filter(f=>f.endsWith('.surql')).sort()) {
    try { await s.query(readFileSync(join(dir,f),'utf8')); } catch {}
  }

  // Create workspace
  const { randomUUID } = require('node:crypto');
  const { RecordId } = require('surrealdb');
  const wsId = randomUUID();
  const ws = new RecordId('workspace', wsId);
  await s.create(ws).content({
    name: 'Debug WS',
    status: 'active',
    onboarding_complete: true,
    onboarding_turn_count: 0,
    onboarding_summary_pending: false,
    onboarding_started_at: new Date(),
    created_at: new Date(),
  });

  // Generate and store API key
  const bytes = require('node:crypto').randomBytes(32);
  const apiKey = 'brain_' + bytes.toString('hex');
  const hash = await Bun.password.hash(apiKey, {algorithm:'bcrypt',cost:10});
  await s.update(ws).merge({api_key_hash: hash});

  console.log(JSON.stringify({wsId, apiKey}));
  await s.close();
}
main();
" 2>/dev/null > /tmp/debug_ws.json

WS_INFO=$(cat /tmp/debug_ws.json)
WS_ID=$(echo "$WS_INFO" | bun -e "const d=JSON.parse(require('fs').readFileSync('/dev/stdin','utf8')); console.log(d.wsId)")
API_KEY=$(echo "$WS_INFO" | bun -e "const d=JSON.parse(require('fs').readFileSync('/dev/stdin','utf8')); console.log(d.apiKey)")

echo "WS: $WS_ID"
echo "KEY: ${API_KEY:0:15}..."

# Start server, capture stderr
SURREAL_NAMESPACE=${NS} SURREAL_DATABASE=${DB} PORT=${PORT} bun run app/server.ts > /tmp/debug_server_out.txt 2>&1 &
SERVER_PID=$!
sleep 3

# Hit the endpoint
RESP=$(curl -s -w "\n%{http_code}" -X POST "http://127.0.0.1:${PORT}/api/mcp/${WS_ID}/context" \
  -H "Content-Type: application/json" \
  -H "Authorization: Bearer ${API_KEY}" \
  -d '{"intent":"What should I work on?"}')

echo "Response: $RESP"
echo "---SERVER LOGS---"
cat /tmp/debug_server_out.txt | tail -30

kill $SERVER_PID 2>/dev/null

