  category?: string;
  description?: string;
  source_session?: RecordId<"agent_session", string>;
};

type QuestionRow = {
  id: RecordId<"question", string>;
  text: string;
  status: string;
  context?: string;
  priority?: string;
};

type ObservationRow = {
  id: RecordId<"observation", string>;
  text: string;
  severity: string;
  status: string;
  category?: string;
  observation_type?: string;
};

type SuggestionRow = {
  id: RecordId<"suggestion", string>;
  text: string;
  category: string;
  rationale: string;
  confidence: number;
  status: string;
  suggested_by: string;
  created_at: Date | string;
};

type AgentSessionRow = {
  id: RecordId<"agent_session", string>;
  agent: string;
  ended_at?: Date | string;
  summary?: string;
};

type SubtaskRow = {
  id: RecordId<"task", string>;
  title: string;
  status: string;
};

type FeatureRow = {
  id: RecordId<"feature", string>;
  name: string;
  description?: string;
};

type DependencyRow = {
  id: RecordId<"task", string>;
  title: string;
