  1→import { describe, expect, it } from "bun:test";
  2→import { randomUUID } from "node:crypto";
  3→import { RecordId, type Surreal } from "surrealdb";
  4→import { generateApiKey, hashApiKey } from "../../app/src/server/mcp/api-key";
  5→import { fetchJson, setupSmokeSuite } from "./smoke-test-kit";
  6→
  7→// ---------------------------------------------------------------------------
  8→// Setup
  9→// ---------------------------------------------------------------------------
 10→
 11→const getRuntime = setupSmokeSuite("intent-context");
 12→
 13→type IntentContextResponse = {
 14→  level: "task" | "project" | "workspace";
 15→  data: Record<string, unknown>;
 16→};
 17→
 18→type AuthedWorkspace = {
 19→  workspaceId: string;
 20→  workspaceRecord: RecordId<"workspace", string>;
 21→  apiKey: string;
 22→};
 23→
 24→async function createWorkspaceWithApiKey(
 25→  baseUrl: string,
 26→  surreal: Surreal,
 27→  name?: string,
 28→): Promise<AuthedWorkspace> {
 29→  const { workspaceId } = await fetchJson<{ workspaceId: string }>(`${baseUrl}/api/workspaces`, {
 30→    method: "POST",
 31→    headers: { "Content-Type": "application/json" },
 32→    body: JSON.stringify({
 33→      name: name ?? `Intent Smoke ${Date.now()}`,
 34→      ownerDisplayName: "Test",
 35→    }),
 36→  });
 37→
 38→  const workspaceRecord = new RecordId("workspace", workspaceId);
 39→  const apiKey = generateApiKey();
 40→  const hash = await hashApiKey(apiKey);
 41→  await surreal.update(workspaceRecord).merge({
 42→    api_key_hash: hash,
 43→    onboarding_complete: true,
 44→    onboarding_summary_pending: false,
 45→    onboarding_completed_at: new Date(),
 46→  });
 47→
 48→  return { workspaceId, workspaceRecord, apiKey };
 49→}
 50→
 51→async function seedProject(
 52→  surreal: Surreal,
 53→  workspaceRecord: RecordId<"workspace", string>,
 54→  name: string,
 55→): Promise<RecordId<"project", string>> {
 56→  const projectRecord = new RecordId("project", randomUUID());
 57→  await surreal.create(projectRecord).content({
 58→    name,
 59→    status: "active",
 60→    workspace: workspaceRecord,
 61→    created_at: new Date(),
 62→    updated_at: new Date(),
 63→  });
 64→  await surreal
 65→    .relate(workspaceRecord, new RecordId("has_project", randomUUID()), projectRecord, {
 66→      added_at: new Date(),
 67→    })
 68→    .output("after");
 69→  return projectRecord;
 70→}
 71→
 72→async function seedTask(
 73→  surreal: Surreal,
 74→  workspaceRecord: RecordId<"workspace", string>,
 75→  projectRecord: RecordId<"project", string>,
 76→  title: string,
 77→): Promise<RecordId<"task", string>> {
 78→  const taskRecord = new RecordId("task", randomUUID());
 79→  await surreal.create(taskRecord).content({
 80→    title,
